clean_county_name &lt;- function(x) {
  x |&gt;
    str_remove_all("\\[[^\\]]*\\]") |&gt;
    str_replace_all("\\s+", " ") |&gt;
    str_trim() |&gt;
    str_remove("\\s+(County|Parish|Borough|Census Area|Municipality)$") |&gt;
    str_to_lower()
}

parse_vote_number &lt;- function(x) {
  x |&gt;
    as.character() |&gt;
    str_remove_all("\\[[^\\]]*\\]") |&gt;
    str_remove_all("[,%]") |&gt;
    str_extract("[0-9]+\\.?[0-9]*") |&gt;
    as.numeric()
}

find_col &lt;- function(nms, patterns) {
  hit &lt;- which(str_detect(nms, regex(str_c(patterns, collapse = "|"), ignore_case = TRUE)))
  if (length(hit) == 0) NA_character_ else nms[hit[1]]
}

standardize_results_table &lt;- function(tbl, state_name, year) {
  names(tbl) &lt;- names(tbl) |&gt;
    str_replace_all("\\n", " ") |&gt;
    str_replace_all("\\s+", " ") |&gt;
    str_trim() |&gt;
    make.unique(sep = "_")

  nms &lt;- names(tbl)
  county_col &lt;- find_col(nms, c("County", "County or equivalent", "Parish", "Borough", "Municipality", "Locality"))
  dem_col &lt;- find_col(nms, c("Biden", "Harris", "Democratic"))
  rep_col &lt;- find_col(nms, c("Trump", "Republican"))
  total_col &lt;- find_col(nms, c("^Total", "Total votes", "Total vote"))

  if (is.na(county_col) || is.na(dem_col) || is.na(rep_col)) {
    stop("Could not identify county, Democratic, or Republican columns for ", state_name, " ", year)
  }

  tbl |&gt;
    transmute(
      state = state_name,
      county_raw = .data[[county_col]],
      dem_votes = parse_vote_number(.data[[dem_col]]),
      rep_votes = parse_vote_number(.data[[rep_col]]),
      total_votes = if (!is.na(total_col)) parse_vote_number(.data[[total_col]]) else NA_real_
    ) |&gt;
    mutate(
      county_clean = clean_county_name(county_raw),
      total_votes = coalesce(total_votes, dem_votes + rep_votes),
      dem_share = dem_votes / total_votes,
      rep_share = rep_votes / total_votes,
      year = year
    ) |&gt;
    filter(!is.na(dem_votes), !is.na(rep_votes), !str_detect(county_clean, "total"))
}

scrape_state_results &lt;- function(state_name, year) {
  wiki_state_name &lt;- if_else(state_name == "Washington", "Washington (state)", state_name)
  cache_file &lt;- file.path("data/mp04", paste0(year, "_", str_replace_all(wiki_state_name, "[ ()]", "_"), ".html"))
  page_title &lt;- paste(year, "United States presidential election in", wiki_state_name)

  if (!file.exists(cache_file)) {
    response &lt;- request("https://en.wikipedia.org") |&gt;
      req_url_path("wiki", page_title) |&gt;
      req_user_agent("STA9750 student project; educational use") |&gt;
      req_perform()
    writeLines(resp_body_string(response), cache_file, useBytes = TRUE)
    Sys.sleep(0.25)
  }

  html &lt;- read_html(cache_file)
  wikitable_nodes &lt;- html |&gt; html_elements("table.wikitable")
  tables &lt;- wikitable_nodes |&gt; html_table(fill = TRUE)
  if (length(tables) == 0) {
    tables &lt;- html_table(html, fill = TRUE)
  }
  county_tables &lt;- keep(tables, function(tbl) {
    any(str_detect(names(tbl), regex("County|Parish|Borough|Municipality|Locality", ignore_case = TRUE)))
  })

  if (length(county_tables) == 0) {
    stop("No county-level table found for ", state_name, " ", year)
  }

  table_attempts &lt;- map(county_tables, function(tbl) {
    tryCatch(
      list(result = standardize_results_table(tbl, state_name, year), error = NULL),
      error = function(e) list(result = NULL, error = conditionMessage(e))
    )
  })

  standardized &lt;- map(table_attempts, "result")
  viable_tables &lt;- compact(standardized) |&gt;
    keep(function(tbl) nrow(tbl) &gt; 1)

  if (length(viable_tables) == 0) {
    table_errors &lt;- compact(map(table_attempts, "error"))
    first_error &lt;- if (length(table_errors) &gt; 0) table_errors[[1]] else "none"
    stop(
      "No viable county result table after standardization for ", state_name, " ", year,
      ". First parser error: ", first_error
    )
  }

  viable_tables[[which.max(map_int(viable_tables, nrow))]]
}

states_with_county_tables &lt;- states |&gt;
  filter(state != "Alaska")

cached_results_file &lt;- "data/mp04/wikipedia_county_results_cache.csv"

if (file.exists(cached_results_file)) {
  wikipedia_results &lt;- read_csv(cached_results_file, show_col_types = FALSE)
  results_2024 &lt;- wikipedia_results |&gt; filter(year == 2024)
  results_2020 &lt;- wikipedia_results |&gt; filter(year == 2020)
} else {
  results_2024 &lt;- map_dfr(states_with_county_tables$state, scrape_state_results, year = 2024)
  results_2020 &lt;- map_dfr(states_with_county_tables$state, scrape_state_results, year = 2020)
  bind_rows(results_2024, results_2020) |&gt;
    write_csv(cached_results_file)
}

if (!all(c("state", "county_clean", "dem_votes", "rep_votes") %in% names(results_2024))) {
  stop("The 2024 Wikipedia scrape did not return usable county-level result columns. Returned columns: ", paste(names(results_2024), collapse = ", "))
}

if (!all(c("state", "county_clean", "dem_votes", "rep_votes") %in% names(results_2020))) {
  stop("The 2020 Wikipedia scrape did not return usable county-level result columns. Returned columns: ", paste(names(results_2020), collapse = ", "))
}


Alaska is omitted from the county-equivalent election-result scrape because the 2020 Wikipedia page states that official borough-level results are not available and does not provide a scrapeable borough/census-area result table. The map below still moves Alaska into a reasonable visual position, but arrows are drawn only for county-equivalent units with comparable 2020 and 2024 Wikipedia table results. Getting the scraper to handle all 49 states took more iteration than I expected — Wikipedia’s table formatting is inconsistent enough between states that I had to add several fallback column-detection patterns before the parser stopped failing on edge cases like Louisiana parishes and Virginia independent cities.

