Task 1: Song Characteristics Dataset
This dataset provides technical metrics (danceability, tempo, key, etc.) for a vast library of songs. We clean the artists column to ensure every artist is individually analyzable.


Code
load_songs &lt;- function() {
  data_dir &lt;- "data/mp03"
  file_path &lt;- file.path(data_dir, "songs.csv")
  url &lt;- "https://raw.githubusercontent.com/gabminamedez/spotify-data/master/data.csv"

  if (!dir.exists(data_dir)) dir.create(data_dir, recursive = TRUE)

  if (!file.exists(file_path)) {
    message("Downloading song data...")
    download.file(url, destfile = file_path, mode = "wb")
  }

  songs_raw &lt;- read_csv(file_path, show_col_types = FALSE)

  clean_artist_string &lt;- function(x) {
    x |&gt;
      str_replace_all("\\['", "") |&gt;
      str_replace_all("'\\]", "") |&gt;
      str_replace_all("'", "") |&gt; 
      str_replace_all(", ", ",")
  }

  songs_clean &lt;- songs_raw |&gt;
    mutate(artists_clean = clean_artist_string(artists)) |&gt;
    separate_longer_delim(artists_clean, delim = ",") |&gt;
    mutate(artist = artists_clean) |&gt;
    select(-artists, -artists_clean)

  return(songs_clean)
}

