Task 2: Playlist Dataset
The Spotify Million Playlist dataset is massive. For this mini-project, we download a subset (slices of 1,000 playlists) and process them into a usable format.


Code
load_playlists &lt;- function(n_slices = 1) {
  data_dir &lt;- "data/mp03"
  if (!dir.exists(data_dir)) dir.create(data_dir, recursive = TRUE)

  base_url &lt;- "https://raw.githubusercontent.com/Devinogrady/spotify_million_playlist_dataset/master/data1/"

  all_playlists &lt;- list()

  for (i in 0:(n_slices - 1)) {
    start_idx &lt;- i * 1000
    end_idx &lt;- start_idx + 999
    filename &lt;- paste0("mpd.slice.", start_idx, "-", end_idx, ".json")
    file_path &lt;- file.path(data_dir, filename)
    file_url &lt;- paste0(base_url, filename)

    # Responsible Download
    if (!file.exists(file_path)) {
      message(paste("Downloading", filename, "..."))
      tryCatch({
         download.file(file_url, destfile = file_path, mode = "wb")
      }, error = function(e) {
        warning(paste("Failed to download", filename, ":", e$message))
      })
    }

    # Read and append to list
    if (file.exists(file_path)) {
      json_data &lt;- fromJSON(file_path, simplifyVector = TRUE)
      if ("playlists" %in% names(json_data)) {
        all_playlists[[length(all_playlists) + 1]] &lt;- as_tibble(json_data$playlists)
      }
    }
  }

  return(all_playlists)
}

# Load 2 slices (approx 2000 playlists)
raw_playlists_list &lt;- load_playlists(n_slices = 2)

Task 3: Rectangling the Data
The playlist data arrives in a nested JSON structure. We “rectangle” it into a tidy dataframe. Per the project requirements, we also ensure we capture the Playlist Position and handle potential missing columns.


Code
strip_spotify_prefix &lt;- function(x) str_remove(x, "spotify:[a-z]+:")

playlists_df &lt;- map_dfr(raw_playlists_list, function(slice) {
  if (nrow(slice) &gt; 0 && "tracks" %in% names(slice)) {
    # Unnest with unique names to prevent collision
    expanded_slice &lt;- slice |&gt; 
      unnest(tracks, names_repair = "unique") |&gt;
      group_by(pid) |&gt;
      mutate(playlist_position = row_number()) |&gt;
      ungroup()

    # Find the duration column dynamically
    dur_col &lt;- names(expanded_slice)[str_detect(names(expanded_slice), "^duration_ms")]

    if (length(dur_col) &gt; 0) {
       expanded_slice &lt;- expanded_slice |&gt; rename(duration_ms_std = !!sym(dur_col[1]))
    } else {
       expanded_slice$duration_ms_std &lt;- NA_real_
    }

    # Ensure all required columns exist
    required_cols &lt;- c("track_uri", "artist_uri", "album_uri", "track_name", 
                       "artist_name", "album_name")
    for (col in required_cols) {
      if (!col %in% names(expanded_slice)) expanded_slice[[col]] &lt;- NA
    }

    expanded_slice |&gt;
      select(
        playlist_name = name,
        playlist_id = pid,
        playlist_position,
        playlist_followers = num_followers,
        track_name,
        track_id = track_uri,
        artist_name,
        artist_id = artist_uri,
        album_name,
        album_id = album_uri,
        duration_ms = duration_ms_std
      )
  } else {
    tibble()
  }
}) |&gt;
  mutate(
    track_id = strip_spotify_prefix(track_id),
    artist_id = strip_spotify_prefix(artist_id),
    album_id = strip_spotify_prefix(album_id),
    duration_ms = as.numeric(duration_ms)
  )

