read_shp_from_zip &lt;- function(zip_path) {
  if (!file.exists(zip_path)) {
    warning(paste("Zip file not found:", zip_path))
    return(NULL)
  }

  td &lt;- tempdir()

  tryCatch({
    # Extract zip contents
    zip_contents &lt;- unzip(zip_path, exdir = td, overwrite = TRUE)

    # Find the .shp file
    fname_shp &lt;- zip_contents[grepl("\\.shp$", zip_contents, ignore.case = TRUE)]

    if (length(fname_shp) == 0) {
      warning(paste("No .shp file found in:", zip_path))
      return(NULL)
    }

    # Read the shapefile
    shp_data &lt;- read_sf(fname_shp[1])

    return(shp_data)
  }, error = function(e) {
    warning(paste("Error reading shapefile from", zip_path, ":", e$message))
    return(NULL)
  })
}

